import { useEffect, useMemo, useState } from "react";
import type { Flag, ReviewArtifact, ReviewItem } from "./types";
import reviewArtifact from "../../../demo-repo/.profiler/review/review-items.json";
import sourceMarkdown from "../../../demo-repo/CLAUDE.md?raw";

interface Segment {
  text: string;
  item: ReviewItem | null;
}

function buildSegments(source: string, items: ReviewItem[]): Segment[] {
  const sorted = [...items].sort((a, b) => a.startOffset - b.startOffset);
  const segs: Segment[] = [];
  let cursor = 0;
  for (const item of sorted) {
    if (item.startOffset > cursor) {
      segs.push({ text: source.slice(cursor, item.startOffset), item: null });
    }
    segs.push({ text: source.slice(item.startOffset, item.endOffset), item });
    cursor = item.endOffset;
  }
  if (cursor < source.length) {
    segs.push({ text: source.slice(cursor), item: null });
  }
  return segs;
}

async function sha256(text: string): Promise<string> {
  const buf = new TextEncoder().encode(text);
  const digest = await crypto.subtle.digest("SHA-256", buf);
  return (
    "sha256:" +
    Array.from(new Uint8Array(digest))
      .map((b) => b.toString(16).padStart(2, "0"))
      .join("")
  );
}

export interface AppProps {
  review?: ReviewArtifact;
  source?: string;
}

export function App({
  review = reviewArtifact as ReviewArtifact,
  source = sourceMarkdown,
}: AppProps = {}) {
  const [sourceHash, setSourceHash] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  useEffect(() => {
    sha256(source).then(setSourceHash);
  }, [source]);

  const segments = useMemo(
    () => buildSegments(source, review.items),
    [source, review.items],
  );

  const selected = useMemo(
    () => review.items.find((i) => i.id === selectedId) ?? null,
    [review, selectedId],
  );

  const drift =
    sourceHash !== null && sourceHash !== review.source.contextHash;

  return (
    <div className="app">
      <Header review={review} drift={drift} />
      {drift && (
        <div role="alert" className="drift-banner">
          Source CLAUDE.md has drifted from the version this report was generated against.
          Re-run the profiler before trusting these recommendations.
        </div>
      )}
      <main>
        <article className="source">
          {segments.map((seg, i) =>
            seg.item ? (
              <Highlight
                key={i}
                item={seg.item}
                text={seg.text}
                selected={seg.item.id === selectedId}
                onSelect={() => setSelectedId(seg.item!.id)}
              />
            ) : (
              <span key={i}>{seg.text}</span>
            ),
          )}
        </article>
        <aside className="detail">
          {selected ? (
            <Detail item={selected} />
          ) : (
            <p className="empty">Click a highlight to inspect.</p>
          )}
        </aside>
      </main>
    </div>
  );
}

function Header({ review, drift }: { review: ReviewArtifact; drift: boolean }) {
  const s = review.summary;
  return (
    <header className="top">
      <h1>Context Profiler</h1>
      <span className="repo">
        {review.source.repoName} / {review.source.contextPath}
      </span>
      <div className="summary">
        <span>{s.totalInstructions} instructions</span>
        <span>{s.totalRuns} runs</span>
        <span>token Δ {s.estimatedTokenChange}</span>
        {drift && <span className="warn">drift</span>}
      </div>
    </header>
  );
}

function Highlight({
  item,
  text,
  selected,
  onSelect,
}: {
  item: ReviewItem;
  text: string;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <mark
      data-testid={`hl-${item.id}`}
      data-verdict={item.verdict}
      className={`hl hl-${item.verdict}${selected ? " selected" : ""}`}
      onClick={onSelect}
    >
      {text}
      <span className="hl-tag" data-testid={`hl-tag-${item.id}`}>
        {item.verdict}
      </span>
    </mark>
  );
}

function Detail({ item }: { item: ReviewItem }) {
  return (
    <>
      <h2>{item.title}</h2>
      <div className="meta">
        <span className={`badge verdict ${item.verdict}`}>{item.verdict}</span>
        <span className="badge status">{item.status}</span>
        {item.flags.map((f: Flag) => (
          <span key={f} className="badge flag">
            {f}
          </span>
        ))}
      </div>
      <p className="reason">{item.reason}</p>
    </>
  );
}
